  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel Tenant {\n  id           String             @id @default(cuid())\n  name         String // Nama Kantor Notaris\n  subdomain    String?            @unique // Subdomain untuk multi-tenancy (Optional)\n  address      String?\n  status       TenantStatus       @default(ACTIVE)\n  subscription TenantSubscription @default(STARTER)\n  createdAt    DateTime           @default(now())\n  updatedAt    DateTime           @updatedAt\n  deletedAt    DateTime?\n\n  users           User[]\n  clients         Client[]\n  deeds           Deed[]\n  appointments    Appointment[]\n  auditLogs       AuditLog[]\n  protocolEntries ProtocolEntry[]\n  invoices        Invoice[]\n}\n\nmodel User {\n  id       String   @id @default(cuid())\n  email    String   @unique\n  password String // Hashed password for local authentication\n  name     String\n  role     UserRole @default(PEGAWAI)\n  tenantId String\n  tenant   Tenant   @relation(fields: [tenantId], references: [id])\n\n  // Password Reset Fields\n  resetToken       String?   @unique\n  resetTokenExpiry DateTime?\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime?\n\n  deedsCreated Deed[]     @relation(\"CreatedBy\")\n  auditLogs    AuditLog[]\n}\n\nmodel Client {\n  id       String @id @default(cuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id])\n\n  // Data sesuai standar Indonesia\n  name    String\n  nik     String  @unique // Nomor Induk Kependudukan\n  address String\n  phone   String?\n  email   String?\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime?\n\n  deeds    Deed[]\n  invoices Invoice[]\n}\n\nmodel Deed {\n  id       String @id @default(cuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id])\n\n  // Metadata Akta\n  title      String\n  type       DeedType // Jenis Akta (Pendirian PT, Jual Beli, dsb)\n  deedNumber String?    @unique // Nomor Akta (jika sudah final)\n  status     DeedStatus @default(DRAFT)\n\n  createdById String\n  createdBy   User   @relation(\"CreatedBy\", fields: [createdById], references: [id])\n\n  clientId String\n  client   Client @relation(fields: [clientId], references: [id])\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime?\n\n  versions        DeedVersion[]\n  protocolEntries ProtocolEntry[]\n  invoices        Invoice[]\n}\n\nmodel DeedVersion {\n  id     String @id @default(cuid())\n  deedId String\n  deed   Deed   @relation(fields: [deedId], references: [id])\n\n  versionNumber Int\n  gcsPath       String // Path ke file di Google Cloud Storage\n  checksum      String? // Untuk integritas file (SHA-256)\n\n  createdAt DateTime @default(now())\n}\n\nmodel ProtocolEntry {\n  id       String @id @default(cuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id])\n\n  deedId String\n  deed   Deed   @relation(fields: [deedId], references: [id])\n\n  repertoriumNumber String // Nomor urut di Repertorium\n  date              DateTime @default(now())\n  description       String? // Sifat akta\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Appointment {\n  id       String @id @default(cuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id])\n\n  title       String\n  startTime   DateTime\n  endTime     DateTime\n  description String?\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime?\n}\n\nmodel AuditLog {\n  id       String @id @default(cuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id])\n\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id])\n\n  action     String // CREATE, UPDATE, DELETE, VIEW_DOCUMENT\n  resource   String // Tabel/Resource yang diakses\n  resourceId String?\n  payload    Json? // Data sebelum/sesudah perubahan\n  ipAddress  String?\n\n  createdAt DateTime @default(now())\n}\n\nenum TenantSubscription {\n  STARTER\n  PROFESSIONAL\n  ENTERPRISE\n}\n\nenum UserRole {\n  NOTARIS\n  PEGAWAI\n  KLIEN\n}\n\nmodel AdminUser {\n  id        String    @id @default(cuid())\n  email     String    @unique\n  password  String // Hashed password for platform admins\n  name      String\n  role      AdminRole @default(STAFF)\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n}\n\nenum AdminRole {\n  SUPERADMIN\n  STAFF\n}\n\nenum TenantStatus {\n  ACTIVE\n  SUSPENDED\n  TRIAL\n}\n\nenum DeedStatus {\n  DRAFT\n  PENDING_CLIENT\n  FINAL\n  INVALIDATED\n}\n\nenum DeedType {\n  PENDIRIAN_PT\n  PENDIRIAN_CV\n  JUAL_BELI\n  SEWA_MENYUWA\n  HIBAH\n  WASIAT\n  KUASA_MENJUAL\n  LAINNYA\n}\n\nmodel Invoice {\n  id       String @id @default(cuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id])\n\n  clientId String\n  client   Client @relation(fields: [clientId], references: [id])\n\n  deedId String?\n  deed   Deed?   @relation(fields: [deedId], references: [id])\n\n  invoiceNumber String        @unique // e.g., INV/2026/001\n  status        InvoiceStatus @default(UNPAID)\n\n  subtotal    Decimal @db.Decimal(15, 2)\n  taxAmount   Decimal @db.Decimal(15, 2) // PPN/PPh\n  totalAmount Decimal @db.Decimal(15, 2)\n\n  dueDate   DateTime?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  items    InvoiceItem[]\n  payments Payment[]\n}\n\nmodel InvoiceItem {\n  id        String  @id @default(cuid())\n  invoiceId String\n  invoice   Invoice @relation(fields: [invoiceId], references: [id])\n\n  description String\n  quantity    Int     @default(1)\n  unitPrice   Decimal @db.Decimal(15, 2)\n  taxable     Boolean @default(true) // Whether PPN applies\n\n  createdAt DateTime @default(now())\n}\n\nmodel Payment {\n  id        String  @id @default(cuid())\n  invoiceId String\n  invoice   Invoice @relation(fields: [invoiceId], references: [id])\n\n  amount Decimal       @db.Decimal(15, 2)\n  method PaymentMethod\n  status PaymentStatus @default(SUCCESS)\n\n  pgTransactionId String? // For Payment Gateway integration\n  paymentDate     DateTime @default(now())\n\n  createdAt DateTime @default(now())\n}\n\nenum InvoiceStatus {\n  UNPAID\n  PARTIAL\n  PAID\n  VOID\n  OVERDUE\n}\n\nenum PaymentMethod {\n  CASH\n  TRANSFER\n  GATEWAY\n}\n\nenum PaymentStatus {\n  PENDING\n  SUCCESS\n  FAILED\n}\n\nmodel DeedTemplate {\n  id      String   @id @default(cuid())\n  title   String // e.g., Pendirian PT Standar\n  type    DeedType\n  content String   @db.Text // Teks struktur dengan [[VARIABLE]]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n",
